import React, { useState, useRef, useCallback } from "react";

// ═══ ICONS ═══
const Ico = ({ d, size=20, color="currentColor", fill="none" }) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill={fill} stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    {typeof d === "string" ? <path d={d}/> : d}
  </svg>
);

// ═══ DEVICE TYPES ═══
const DEVICE_TYPES = {
  switch: {
    label: "Switch",
    color: "#1d4ed8",
    bg: "#eff6ff",
    icon: (
      <>
        <rect x="2" y="2" width="20" height="8" rx="2"/>
        <rect x="2" y="14" width="20" height="8" rx="2"/>
        <line x1="6" y1="6" x2="6.01" y2="6"/>
        <line x1="6" y1="18" x2="6.01" y2="18"/>
      </>
    ),
    defaultName: "Switch",
    interfaces: ["GigabitEthernet0/0","GigabitEthernet0/1","GigabitEthernet0/2","GigabitEthernet0/3"],
    initCommands: [],
  },
  router: {
    label: "Router",
    color: "#15803d",
    bg: "#f0fdf4",
    icon: (
      <>
        <path d="M5 12.55a11 11 0 0 1 14.08 0"/>
        <path d="M1.42 9a16 16 0 0 1 21.16 0"/>
        <path d="M8.53 16.11a6 6 0 0 1 6.95 0"/>
        <line x1="12" y1="20" x2="12.01" y2="20"/>
      </>
    ),
    defaultName: "Router",
    interfaces: ["GigabitEthernet0/0","GigabitEthernet0/1","Serial0/0/0","Serial0/0/1"],
    initCommands: [],
  },
  pc: {
    label: "PC",
    color: "#374151",
    bg: "#f9fafb",
    icon: (
      <>
        <rect x="2" y="3" width="20" height="14" rx="2"/>
        <path d="M8 21h8M12 17v4"/>
      </>
    ),
    defaultName: "PC",
    interfaces: ["FastEthernet0"],
    initCommands: [],
  },
  firewall: {
    label: "Firewall",
    color: "#b91c1c",
    bg: "#fef2f2",
    icon: <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/>,
    defaultName: "Firewall",
    interfaces: ["GigabitEthernet0/0","GigabitEthernet0/1","GigabitEthernet0/2"],
    initCommands: [],
  },
  server: {
    label: "Server",
    color: "#7c3aed",
    bg: "#fdf4ff",
    icon: (
      <>
        <rect x="2" y="2" width="20" height="8" rx="2"/>
        <rect x="2" y="14" width="20" height="8" rx="2"/>
        <line x1="6" y1="6" x2="6.01" y2="6"/>
        <line x1="6" y1="18" x2="6.01" y2="18"/>
        <line x1="10" y1="6" x2="10.01" y2="6"/>
        <line x1="10" y1="18" x2="10.01" y2="18"/>
      </>
    ),
    defaultName: "Server",
    interfaces: ["FastEthernet0","FastEthernet1"],
    initCommands: [],
  },
};

// ═══ TERMINAL ═══
const lineColors = { header:"#60a5fa", success:"#34d399", warn:"#fbbf24", error:"#f87171", info:"#a78bfa", muted:"#475569", text:"#e2e8f0" };

const DeviceTerminal = ({ device, onClose, onCommand }) => {
  const [input, setInput] = useState("");
  const [lines, setLines] = useState([
    { t:"info", v:`Connected to ${device.name} (${DEVICE_TYPES[device.type].label})` },
    { t:"muted", v:"Type commands below. Type ? for help." },
    { t:"muted", v:"" },
  ]);
  const [mode, setMode] = useState("privileged");
  const [hostname, setHostname] = useState(device.name);
  const [history, setHistory] = useState([]);
  const [histIdx, setHistIdx] = useState(-1);
  const termRef = useRef(null);
  const inputRef = useRef(null);

  const prompt = { user:`${hostname}>`, privileged:`${hostname}#`, config:`${hostname}(config)#`, interface:`${hostname}(config-if)#` }[mode] || `${hostname}#`;

  const addLines = (newLines) => {
    setLines(prev => [...prev, ...newLines]);
    setTimeout(() => { if(termRef.current) termRef.current.scrollTop = termRef.current.scrollHeight; }, 30);
  };

  const handleKey = (e) => {
    if (e.key === "Enter") {
      const cmd = input.trim();
      setInput(""); setHistIdx(-1);
      if (cmd) setHistory(prev => [cmd, ...prev]);
      addLines([{ t:"prompt-line", prompt, cmd }]);
      processCmd(cmd);
    } else if (e.key === "ArrowUp") {
      e.preventDefault();
      const i = histIdx + 1;
      if (i < history.length) { setHistIdx(i); setInput(history[i]); }
    } else if (e.key === "ArrowDown") {
      e.preventDefault();
      const i = histIdx - 1;
      if (i < 0) { setHistIdx(-1); setInput(""); }
      else { setHistIdx(i); setInput(history[i]); }
    }
  };

  const processCmd = (raw) => {
    const cmd = raw.toLowerCase().trim();
    const parts = cmd.split(/\s+/);
    const ts = () => { const n = new Date(); return `*${n.toLocaleDateString("en-US",{month:"short",day:"2-digit",year:"numeric"})} ${n.toTimeString().slice(0,8)}`; };

    if (!cmd) return;

    if (cmd === "?" || cmd === "help") {
      addLines([
        { t:"header", v:"Available Commands:" },
        { t:"info", v:"  enable                 Enter privileged mode" },
        { t:"info", v:"  configure terminal     Enter config mode" },
        { t:"info", v:"  hostname <name>        Set hostname" },
        { t:"info", v:"  interface <name>       Enter interface config" },
        { t:"info", v:"  ip address <ip> <mask> Assign IP address" },
        { t:"info", v:"  no shutdown            Enable interface" },
        { t:"info", v:"  shutdown               Disable interface" },
        { t:"info", v:"  show ip interface brief Show interfaces" },
        { t:"info", v:"  show running-config    Show config" },
        { t:"info", v:"  write memory           Save config" },
        { t:"info", v:"  end / exit             Change mode" },
        { t:"info", v:"  clear                  Clear screen" },
      ]);
      return;
    }

    if (cmd === "clear" || cmd === "cls") { setLines([]); return; }

    if (cmd === "enable" || cmd === "en") {
      if (mode === "user") { setMode("privileged"); addLines([{ t:"success", v:"Entering privileged EXEC mode..." }]); }
      else addLines([{ t:"warn", v:"Already in privileged mode." }]);
      return;
    }

    if (cmd === "disable") { setMode("user"); addLines([{ t:"muted", v:"" }]); return; }

    if (cmd === "configure terminal" || cmd === "conf t") {
      if (mode !== "privileged") { addLines([{ t:"error", v:"% Must be in privileged mode." }]); return; }
      setMode("config");
      addLines([{ t:"info", v:"Enter configuration commands, one per line. End with CNTL/Z." }]);
      onCommand && onCommand(device.id, raw);
      return;
    }

    if (cmd === "end" || cmd === "exit") {
      if (mode === "interface") setMode("config");
      else if (mode === "config") { setMode("privileged"); addLines([{ t:"success", v:`${ts()}: %SYS-5-CONFIG_I: Configured from console` }]); }
      else if (mode === "privileged") setMode("user");
      return;
    }

    if (parts[0] === "hostname" && parts[1]) {
      if (mode !== "config") { addLines([{ t:"error", v:"% Must be in config mode." }]); return; }
      setHostname(parts[1]);
      onCommand && onCommand(device.id, raw, { hostname: parts[1] });
      addLines([{ t:"success", v:`Hostname changed to '${parts[1]}'` }]);
      return;
    }

    if (parts[0] === "interface" || parts[0] === "int") {
      if (mode !== "config") { addLines([{ t:"error", v:"% Must be in config mode." }]); return; }
      const ifName = parts.slice(1).join(" ").replace(/^gi/i,"GigabitEthernet").replace(/^fa/i,"FastEthernet").replace(/^se/i,"Serial");
      setMode("interface");
      addLines([{ t:"info", v:`Entering interface config for ${ifName}` }]);
      onCommand && onCommand(device.id, raw);
      return;
    }

    if (parts[0] === "ip" && parts[1] === "address" && parts[2] && parts[3]) {
      if (mode !== "interface") { addLines([{ t:"error", v:"% Must be in interface config mode." }]); return; }
      addLines([{ t:"success", v:`IP address ${parts[2]} ${parts[3]} assigned.` }]);
      onCommand && onCommand(device.id, raw, { ip: parts[2], mask: parts[3] });
      return;
    }

    if (cmd === "no shutdown" || cmd === "no shut") {
      if (mode !== "interface") { addLines([{ t:"error", v:"% Must be in interface config mode." }]); return; }
      addLines([
        { t:"success", v:`${ts()}: %LINK-3-UPDOWN: Interface changed state to up` },
        { t:"success", v:`${ts()}: %LINEPROTO-5-UPDOWN: Line protocol changed state to up` },
      ]);
      onCommand && onCommand(device.id, raw);
      return;
    }

    if (cmd === "shutdown" || cmd === "shut") {
      if (mode !== "interface") { addLines([{ t:"error", v:"% Must be in interface config mode." }]); return; }
      addLines([{ t:"warn", v:`${ts()}: %LINK-5-CHANGED: Interface changed state to administratively down` }]);
      onCommand && onCommand(device.id, raw);
      return;
    }

    if (cmd === "show ip interface brief" || cmd === "sh ip int br") {
      const ifaces = DEVICE_TYPES[device.type].interfaces;
      addLines([{ t:"header", v:"Interface              IP-Address      OK? Method Status                Protocol" }]);
      ifaces.forEach((iface, i) => {
        const short = iface.replace("GigabitEthernet","Gi").replace("FastEthernet","Fa").replace("Serial","Se");
        addLines([{ t: i===0?"success":"warn", v:`${short.padEnd(23)}${"unassigned".padEnd(16)}NO  unset  ${"down".padEnd(22)}down` }]);
      });
      return;
    }

    if (cmd === "show running-config" || cmd === "sh run") {
      addLines([
        { t:"info", v:"Building configuration..." },
        { t:"header", v:"Current configuration:" },
        { t:"muted", v:"!" },
        { t:"text", v:`hostname ${hostname}` },
        { t:"muted", v:"!" },
        { t:"text", v:"end" },
      ]);
      return;
    }

    if (cmd === "write memory" || cmd === "wr") {
      addLines([{ t:"info", v:"Building configuration..." }, { t:"success", v:"[OK]" }]);
      return;
    }

    addLines([{ t:"error", v:`% Unrecognized command: '${raw}'. Type ? for help.` }]);
  };

  return (
    <div style={{ position:"fixed", inset:0, background:"#00000088", backdropFilter:"blur(4px)", display:"flex", alignItems:"center", justifyContent:"center", zIndex:300 }}>
      <div style={{ width:640, height:480, background:"#0f172a", borderRadius:14, display:"flex", flexDirection:"column", boxShadow:"0 24px 60px #00000055", overflow:"hidden" }}>
        <div style={{ background:"#1e293b", padding:"10px 16px", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
          <div style={{ display:"flex", alignItems:"center", gap:10 }}>
            <div style={{ display:"flex", gap:6 }}>
              <div style={{ width:11, height:11, borderRadius:"50%", background:"#ef4444" }}/>
              <div style={{ width:11, height:11, borderRadius:"50%", background:"#f59e0b" }}/>
              <div style={{ width:11, height:11, borderRadius:"50%", background:"#10b981" }}/>
            </div>
            <span style={{ fontSize:12, color:"#64748b", fontFamily:"monospace" }}>{device.name} — {DEVICE_TYPES[device.type].label} Terminal</span>
          </div>
          <button onClick={onClose} style={{ background:"#334155", border:"none", color:"#94a3b8", width:24, height:24, borderRadius:4, cursor:"pointer", fontSize:14 }}>x</button>
        </div>
        <div ref={termRef} style={{ flex:1, overflowY:"auto", padding:"14px 18px", fontFamily:"monospace", fontSize:13, lineHeight:1.7 }} onClick={()=>inputRef.current?.focus()}>
          {lines.map((line, i) => {
            if (line.t === "prompt-line") return (
              <div key={i}><span style={{ color:"#10b981", fontWeight:700 }}>{line.prompt} </span><span style={{ color:"#f8fafc" }}>{line.cmd}</span></div>
            );
            return <div key={i} style={{ color: lineColors[line.t]||lineColors.text }}>{line.v||"\u00A0"}</div>;
          })}
          <div style={{ display:"flex", alignItems:"center" }}>
            <span style={{ color:"#10b981", fontWeight:700, marginRight:6 }}>{prompt}</span>
            <input ref={inputRef} value={input} onChange={e=>setInput(e.target.value)} onKeyDown={handleKey} autoFocus
              style={{ background:"transparent", border:"none", outline:"none", color:"#f8fafc", fontFamily:"monospace", fontSize:13, flex:1 }}
              spellCheck={false} autoComplete="off" />
          </div>
        </div>
        <div style={{ background:"#1e293b", padding:"5px 16px", fontSize:10, color:"#475569", display:"flex", gap:16 }}>
          <span>Up/Down: History</span><span>?: Help</span><span>clear: Clear</span>
        </div>
      </div>
    </div>
  );
};

// ═══ TOPOLOGY BUILDER ═══
const TopologyBuilder = () => {
  const [devices, setDevices] = useState([
    { id:"sw1", type:"switch", name:"Switch1", x:300, y:200 },
    { id:"rt1", type:"router", name:"Router1", x:550, y:200 },
    { id:"pc1", type:"pc", name:"PC1", x:150, y:350 },
    { id:"pc2", type:"pc", name:"PC2", x:300, y:380 },
  ]);
  const [links, setLinks] = useState([
    { id:"l1", from:"pc1", to:"sw1" },
    { id:"l2", from:"pc2", to:"sw1" },
    { id:"l3", from:"sw1", to:"rt1" },
  ]);
  const [dragging, setDragging] = useState(null);
  const [offset, setOffset] = useState({ x:0, y:0 });
  const [linking, setLinking] = useState(null);
  const [selectedDevice, setSelectedDevice] = useState(null);
  const [terminalDevice, setTerminalDevice] = useState(null);
  const [terminalLog, setTerminalLog] = useState([]);
  const [tool, setTool] = useState("select");
  const canvasRef = useRef(null);
  const counter = useRef(10);

  const getCenter = (dev) => ({ x: dev.x + 40, y: dev.y + 40 });

  const handleMouseDown = (e, dev) => {
    e.stopPropagation();
    if (tool === "link") {
      if (!linking) { setLinking(dev.id); }
      else if (linking !== dev.id) {
        const exists = links.find(l => (l.from===linking&&l.to===dev.id)||(l.from===dev.id&&l.to===linking));
        if (!exists) setLinks(prev => [...prev, { id:`l${Date.now()}`, from:linking, to:dev.id }]);
        setLinking(null);
      }
      return;
    }
    if (tool === "delete") {
      setDevices(prev => prev.filter(d => d.id !== dev.id));
      setLinks(prev => prev.filter(l => l.from !== dev.id && l.to !== dev.id));
      return;
    }
    setDragging(dev.id);
    setOffset({ x: e.clientX - dev.x, y: e.clientY - dev.y });
    setSelectedDevice(dev.id);
  };

  const handleMouseMove = useCallback((e) => {
    if (!dragging) return;
    const canvas = canvasRef.current?.getBoundingClientRect();
    if (!canvas) return;
    setDevices(prev => prev.map(d => d.id === dragging ? { ...d, x: Math.max(0, Math.min(e.clientX - offset.x, canvas.width - 80)), y: Math.max(0, Math.min(e.clientY - offset.y, canvas.height - 80)) } : d));
  }, [dragging, offset]);

  const handleMouseUp = () => setDragging(null);

  const addDevice = (type) => {
    counter.current++;
    const label = DEVICE_TYPES[type].defaultName;
    setDevices(prev => [...prev, { id:`${type}${counter.current}`, type, name:`${label}${counter.current}`, x:200 + Math.random()*200, y:150 + Math.random()*150 }]);
  };

  const deleteLink = (linkId) => {
    setLinks(prev => prev.filter(l => l.id !== linkId));
  };

  const handleCommand = (deviceId, cmd, meta) => {
    setTerminalLog(prev => [...prev, { deviceId, cmd, meta, time: new Date().toLocaleTimeString() }]);
  };

  const dev = selectedDevice ? devices.find(d => d.id === selectedDevice) : null;

  return (
    <div style={{ flex:1, display:"flex", flexDirection:"column", background:"#f8fafc", overflow:"hidden" }}>

      {/* TOOLBAR */}
      <div style={{ background:"#fff", borderBottom:"1px solid #e5e7eb", padding:"8px 16px", display:"flex", alignItems:"center", gap:8, flexWrap:"wrap" }}>
        <span style={{ fontSize:11, fontWeight:700, color:"#9ca3af", marginRight:4 }}>ADD:</span>
        {Object.entries(DEVICE_TYPES).map(([type, info]) => (
          <button key={type} onClick={()=>addDevice(type)} style={{ background:`${info.color}12`, border:`1px solid ${info.color}40`, color:info.color, padding:"5px 12px", borderRadius:6, cursor:"pointer", fontSize:11, fontWeight:700, display:"flex", alignItems:"center", gap:5 }}>
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke={info.color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">{info.icon}</svg>
            {info.label}
          </button>
        ))}

        <div style={{ width:1, background:"#e5e7eb", height:24, margin:"0 4px" }}/>
        <span style={{ fontSize:11, fontWeight:700, color:"#9ca3af", marginRight:4 }}>TOOL:</span>

        {[
          { id:"select", label:"Select", icon:<><path d="M3 3l7.07 16.97 2.51-7.39 7.39-2.51L3 3z"/><path d="M13 13l6 6"/></> },
          { id:"link", label:"Link", icon:<><line x1="4" y1="9" x2="20" y2="9"/><line x1="4" y1="15" x2="20" y2="15"/></> },
          { id:"delete", label:"Delete", icon:<><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2"/></> },
        ].map(t => (
          <button key={t.id} onClick={()=>{ setTool(t.id); setLinking(null); }} style={{ background: tool===t.id ? "#1d4ed8" : "#f3f4f6", border:"1px solid", borderColor: tool===t.id ? "#1d4ed8" : "#e5e7eb", color: tool===t.id ? "#fff" : "#374151", padding:"5px 12px", borderRadius:6, cursor:"pointer", fontSize:11, fontWeight:700, display:"flex", alignItems:"center", gap:5 }}>
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">{t.icon}</svg>
            {t.label}
          </button>
        ))}

        {linking && <div style={{ background:"#fef3c7", border:"1px solid #fde68a", color:"#92400e", padding:"4px 12px", borderRadius:6, fontSize:11, fontWeight:600 }}>Click another device to link...</div>}
      </div>

      <div style={{ flex:1, display:"flex", overflow:"hidden" }}>

        {/* CANVAS */}
        <div ref={canvasRef} style={{ flex:1, position:"relative", background:"#f1f5f9", backgroundImage:"radial-gradient(#cbd5e1 1px, transparent 1px)", backgroundSize:"24px 24px", cursor: tool==="link"?"crosshair":tool==="delete"?"not-allowed":"default", overflow:"hidden" }}
          onMouseMove={handleMouseMove} onMouseUp={handleMouseUp}
          onClick={()=>{ if(tool==="select") setSelectedDevice(null); }}>

          {/* SVG LINKS */}
          <svg style={{ position:"absolute", inset:0, width:"100%", height:"100%", pointerEvents:"none" }}>
            {links.map(link => {
              const from = devices.find(d => d.id === link.from);
              const to = devices.find(d => d.id === link.to);
              if (!from || !to) return null;
              const fc = getCenter(from); const tc = getCenter(to);
              const mx = (fc.x + tc.x) / 2; const my = (fc.y + tc.y) / 2;
              return (
                <g key={link.id}>
                  <line x1={fc.x} y1={fc.y} x2={tc.x} y2={tc.y} stroke="#94a3b8" strokeWidth="2" strokeDasharray="6,3"/>
                  <circle cx={mx} cy={my} r="8" fill="#fff" stroke="#e5e7eb" strokeWidth="1" style={{ cursor:"pointer", pointerEvents:"all" }} onClick={()=>deleteLink(link.id)}/>
                  <text x={mx} y={my+4} textAnchor="middle" fontSize="10" fill="#ef4444" style={{ pointerEvents:"all", cursor:"pointer" }} onClick={()=>deleteLink(link.id)}>x</text>
                </g>
              );
            })}
          </svg>

          {/* DEVICES */}
          {devices.map(dev => {
            const info = DEVICE_TYPES[dev.type];
            const isSelected = selectedDevice === dev.id;
            const isLinking = linking === dev.id;
            return (
              <div key={dev.id}
                style={{ position:"absolute", left:dev.x, top:dev.y, width:80, height:80, cursor: tool==="select"?"grab":tool==="link"?"crosshair":"not-allowed", userSelect:"none" }}
                onMouseDown={e=>handleMouseDown(e, dev)}
                onDoubleClick={()=>{ if(tool==="select") setTerminalDevice(dev); }}>
                <div style={{ width:80, height:80, background:info.bg, border:`2px solid ${isSelected||isLinking ? info.color : "#e5e7eb"}`, borderRadius:12, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", gap:4, boxShadow: isSelected ? `0 0 0 3px ${info.color}33` : "0 2px 8px #00000015", transition:"all 0.1s" }}>
                  <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke={info.color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">{info.icon}</svg>
                </div>
                <div style={{ textAlign:"center", fontSize:10, fontWeight:700, color:"#374151", marginTop:4, whiteSpace:"nowrap" }}>{dev.name}</div>
              </div>
            );
          })}
        </div>

        {/* RIGHT PANEL */}
        <div style={{ width:220, background:"#fff", borderLeft:"1px solid #e5e7eb", display:"flex", flexDirection:"column" }}>

          {/* DEVICE PROPERTIES */}
          <div style={{ padding:"12px", borderBottom:"1px solid #f3f4f6" }}>
            <div style={{ fontSize:10, color:"#9ca3af", textTransform:"uppercase", letterSpacing:1, marginBottom:8 }}>Properties</div>
            {dev ? (
              <>
                <div style={{ fontSize:12, fontWeight:700, color:"#111827", marginBottom:8 }}>{DEVICE_TYPES[dev.type].label}</div>
                <input value={dev.name} onChange={e=>setDevices(prev=>prev.map(d=>d.id===dev.id?{...d,name:e.target.value}:d))}
                  style={{ width:"100%", padding:"6px 10px", border:"1px solid #e5e7eb", borderRadius:6, fontSize:12, outline:"none", marginBottom:8, boxSizing:"border-box" }} />
                <div style={{ fontSize:10, color:"#9ca3af", marginBottom:6 }}>Interfaces:</div>
                {DEVICE_TYPES[dev.type].interfaces.map((iface,i) => (
                  <div key={i} style={{ fontSize:10, color:"#374151", padding:"3px 6px", background:"#f8fafc", borderRadius:4, marginBottom:3, fontFamily:"monospace" }}>{iface.replace("GigabitEthernet","Gi").replace("FastEthernet","Fa")}</div>
                ))}
                <button onClick={()=>setTerminalDevice(dev)} style={{ width:"100%", marginTop:10, background:"#0f172a", border:"none", color:"#10b981", padding:"8px", borderRadius:8, cursor:"pointer", fontSize:11, fontWeight:700, fontFamily:"monospace" }}>
                  Open Terminal
                </button>
              </>
            ) : (
              <div style={{ fontSize:11, color:"#9ca3af" }}>Click a device to select it. Double-click to open terminal.</div>
            )}
          </div>

          {/* COMMAND LOG */}
          <div style={{ flex:1, padding:"12px", overflowY:"auto" }}>
            <div style={{ fontSize:10, color:"#9ca3af", textTransform:"uppercase", letterSpacing:1, marginBottom:8 }}>Command Log</div>
            {terminalLog.length === 0 && <div style={{ fontSize:11, color:"#9ca3af" }}>No commands yet.</div>}
            {terminalLog.map((entry, i) => {
              const d = devices.find(x => x.id === entry.deviceId);
              const info = d ? DEVICE_TYPES[d.type] : null;
              return (
                <div key={i} style={{ marginBottom:8, padding:"6px 8px", background:"#f8fafc", borderRadius:6, borderLeft:`3px solid ${info?.color||"#e5e7eb"}` }}>
                  <div style={{ fontSize:9, color:"#9ca3af", marginBottom:2 }}>{d?.name} — {entry.time}</div>
                  <div style={{ fontSize:11, fontFamily:"monospace", color:"#374151" }}>{entry.cmd}</div>
                </div>
              );
            })}
          </div>

          <div style={{ padding:"8px 12px", borderTop:"1px solid #f3f4f6", fontSize:10, color:"#9ca3af", lineHeight:1.6 }}>
            <div>Drag: Move device</div>
            <div>Double-click: Open terminal</div>
            <div>Link tool: Connect devices</div>
            <div>x on cable: Delete link</div>
          </div>
        </div>
      </div>

      {terminalDevice && (
        <DeviceTerminal
          device={terminalDevice}
          onClose={()=>setTerminalDevice(null)}
          onCommand={handleCommand}
        />
      )}
    </div>
  );
};

// ═══ CONFIG MODALS ═══
const Modal = ({ title, onClose, children }) => (
  <div style={{ position:"fixed", inset:0, background:"#00000077", backdropFilter:"blur(4px)", display:"flex", alignItems:"center", justifyContent:"center", zIndex:200 }}>
    <div style={{ background:"#fff", borderRadius:16, padding:"28px 32px", width:420, boxShadow:"0 24px 60px #00000025", maxHeight:"90vh", overflowY:"auto" }}>
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:20 }}>
        <div style={{ fontSize:16, fontWeight:700, color:"#111827" }}>{title}</div>
        <button onClick={onClose} style={{ background:"#f3f4f6", border:"none", borderRadius:6, width:28, height:28, cursor:"pointer", fontSize:16, color:"#6b7280" }}>x</button>
      </div>
      {children}
    </div>
  </div>
);
const Field = ({ label, value, onChange, placeholder, type="text" }) => (
  <div style={{ marginBottom:14 }}>
    <div style={{ fontSize:11, fontWeight:600, color:"#374151", marginBottom:5 }}>{label}</div>
