      style={{ width:"100%", padding:"9px 12px", border:"1px solid #e5e7eb", borderRadius:8, fontSize:13, outline:"none", fontFamily:"monospace", boxSizing:"border-box", background:"#f9fafb", color:"#111827" }} />
  </div>
);
const Sel = ({ label, value, onChange, options }) => (
  <div style={{ marginBottom:14 }}>
    <div style={{ fontSize:11, fontWeight:600, color:"#374151", marginBottom:5 }}>{label}</div>
    <select value={value} onChange={e=>onChange(e.target.value)}
      style={{ width:"100%", padding:"9px 12px", border:"1px solid #e5e7eb", borderRadius:8, fontSize:13, outline:"none", boxSizing:"border-box", background:"#f9fafb", color:"#111827" }}>
      {options.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
    </select>
  </div>
);
const ApplyBtn = ({ onClick, label="Apply" }) => (
  <div style={{ display:"flex", justifyContent:"flex-end", marginTop:20 }}>
    <button onClick={onClick} style={{ background:"#1d4ed8", border:"none", color:"#fff", padding:"10px 24px", borderRadius:8, cursor:"pointer", fontSize:13, fontWeight:700 }}>{label}</button>
