);
const InfoBox = ({ text }) => (
  <div style={{ background:"#eff6ff", border:"1px solid #bfdbfe", borderRadius:8, padding:"10px 14px", fontSize:11, color:"#1e40af", marginBottom:16 }}>{text}</div>
);

const ifaces = ["GigabitEthernet0/0","GigabitEthernet0/1","GigabitEthernet0/2","GigabitEthernet0/3","Vlan1"];

const IPModal = ({ onClose, onCommand }) => {
  const [iface, setIface] = useState("GigabitEthernet0/0"); const [ip, setIp] = useState(""); const [mask, setMask] = useState("255.255.255.0");
  const apply = () => { if(!ip) return; onCommand("configure terminal"); setTimeout(()=>{ onCommand(`interface ${iface}`); setTimeout(()=>{ onCommand(`ip address ${ip} ${mask}`); setTimeout(()=>{ onCommand("no shutdown"); setTimeout(()=>onCommand("end"),200); },200); },200); },200); onClose(); };
  return (<Modal title="Set IP Address" onClose={onClose}><InfoBox text="Assign an IP address to a network interface." /><Sel label="Interface" value={iface} onChange={setIface} options={ifaces.map(i=>({value:i,label:i}))} /><Field label="IP Address" value={ip} onChange={setIp} placeholder="e.g. 192.168.1.1" /><Field label="Subnet Mask" value={mask} onChange={setMask} placeholder="e.g. 255.255.255.0" /><ApplyBtn onClick={apply} label="Assign IP" /></Modal>);
};
const PortModal = ({ onClose, onCommand }) => {
  const [iface, setIface] = useState("GigabitEthernet0/1"); const [action, setAction] = useState("enable");
  const apply = () => { onCommand("configure terminal"); setTimeout(()=>{ onCommand(`interface ${iface}`); setTimeout(()=>{ onCommand(action==="enable"?"no shutdown":"shutdown"); setTimeout(()=>onCommand("end"),200); },200); },200); onClose(); };
  return (<Modal title="Enable / Disable Port" onClose={onClose}><InfoBox text="Control port state." /><Sel label="Interface" value={iface} onChange={setIface} options={ifaces.map(i=>({value:i,label:i}))} /><Sel label="Action" value={action} onChange={setAction} options={[{value:"enable",label:"Enable (no shutdown)"},{value:"disable",label:"Disable (shutdown)"}]} /><ApplyBtn onClick={apply} label="Apply" /></Modal>);
};
const VLANModal = ({ onClose, onCommand }) => {
  const [vlanId, setVlanId] = useState(""); const [vlanName, setVlanName] = useState(""); const [iface, setIface] = useState("GigabitEthernet0/1"); const [mode, setMode] = useState("access");
  const apply = () => { if(!vlanId) return; onCommand("configure terminal"); setTimeout(()=>{ onCommand(`vlan ${vlanId}`); setTimeout(()=>{ if(vlanName) onCommand(`name ${vlanName}`); setTimeout(()=>{ onCommand("exit"); setTimeout(()=>{ onCommand(`interface ${iface}`); setTimeout(()=>{ onCommand(`switchport mode ${mode}`); setTimeout(()=>{ onCommand(`switchport access vlan ${vlanId}`); setTimeout(()=>onCommand("end"),200); },200); },200); },200); },200); },200); },200); onClose(); };
  return (<Modal title="Configure VLAN" onClose={onClose}><InfoBox text="Create a VLAN and assign to interface." /><Field label="VLAN ID" value={vlanId} onChange={setVlanId} placeholder="e.g. 10" /><Field label="VLAN Name" value={vlanName} onChange={setVlanName} placeholder="e.g. Management" /><Sel label="Interface" value={iface} onChange={setIface} options={ifaces.map(i=>({value:i,label:i}))} /><Sel label="Mode" value={mode} onChange={setMode} options={[{value:"access",label:"Access"},{value:"trunk",label:"Trunk"}]} /><ApplyBtn onClick={apply} label="Create VLAN" /></Modal>);
};
const HostnameModal2 = ({ onClose, onCommand }) => {
  const [name, setName] = useState("");
  const apply = () => { if(!name) return; onCommand("configure terminal"); setTimeout(()=>{ onCommand(`hostname ${name}`); setTimeout(()=>onCommand("end"),200); },200); onClose(); };
  return (<Modal title="Change Hostname" onClose={onClose}><InfoBox text="Set device hostname." /><Field label="New Hostname" value={name} onChange={setName} placeholder="e.g. CoreSwitch" /><ApplyBtn onClick={apply} label="Change" /></Modal>);
};
const SaveModal = ({ onClose, onCommand }) => { const apply = () => { onCommand("write memory"); onClose(); }; return (<Modal title="Save Configuration" onClose={onClose}><InfoBox text="Save running config to NVRAM." /><div style={{ fontSize:13, color:"#374151", marginBottom:16 }}>Executes: <code>write memory</code></div><ApplyBtn onClick={apply} label="Save Now" /></Modal>); };
const ShowModal = ({ onClose, onCommand }) => {
  const [cmd, setCmd] = useState("show ip interface brief");
  const apply = () => { onCommand(cmd); onClose(); };
  return (<Modal title="Show Status" onClose={onClose}><InfoBox text="View network information." /><Sel label="Command" value={cmd} onChange={setCmd} options={[{value:"show ip interface brief",label:"Interface Status"},{value:"show running-config",label:"Running Config"},{value:"show version",label:"IOS Version"},{value:"show vlan brief",label:"VLAN Table"},{value:"show interfaces",label:"All Interfaces"}]} /><ApplyBtn onClick={apply} label="Show" /></Modal>);
};
const RouteModal = ({ onClose, onCommand }) => {
  const [net, setNet] = useState(""); const [mask, setMask] = useState("255.255.255.0"); const [gw, setGw] = useState("");
  const apply = () => { if(!net||!gw) return; onCommand("configure terminal"); setTimeout(()=>{ onCommand(`ip route ${net} ${mask} ${gw}`); setTimeout(()=>onCommand("end"),200); },200); onClose(); };
  return (<Modal title="Static Route" onClose={onClose}><InfoBox text="Add a static route." /><Field label="Destination Network" value={net} onChange={setNet} placeholder="e.g. 192.168.2.0" /><Field label="Subnet Mask" value={mask} onChange={setMask} placeholder="e.g. 255.255.255.0" /><Field label="Next Hop" value={gw} onChange={setGw} placeholder="e.g. 192.168.1.254" /><ApplyBtn onClick={apply} label="Add Route" /></Modal>);
};

// ═══ CARD ═══
const Card = ({ icon, title, desc, color, onClick }) => (
  <button onClick={onClick} style={{ background:"#fff", border:"1px solid #e5e7eb", borderRadius:14, padding:"20px 18px", cursor:"pointer", textAlign:"left", transition:"all 0.15s", display:"flex", flexDirection:"column", gap:10, boxShadow:"0 1px 3px #0000000a" }}
    onMouseEnter={e=>{ e.currentTarget.style.transform="translateY(-2px)"; e.currentTarget.style.boxShadow=`0 8px 24px ${color}22`; e.currentTarget.style.borderColor=color; }}
    onMouseLeave={e=>{ e.currentTarget.style.transform="translateY(0)"; e.currentTarget.style.boxShadow="0 1px 3px #0000000a"; e.currentTarget.style.borderColor="#e5e7eb"; }}>
    <div style={{ width:44, height:44, borderRadius:12, background:`${color}15`, display:"flex", alignItems:"center", justifyContent:"center" }}>
      <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">{icon}</svg>
    </div>
    <div>
      <div style={{ fontSize:13, fontWeight:700, color:"#111827", marginBottom:3 }}>{title}</div>
      <div style={{ fontSize:11, color:"#9ca3af", lineHeight:1.5 }}>{desc}</div>
    </div>
  </button>
);

// ═══ MAIN ═══
export default function GUI({ onCommand }) {
  const [modal, setModal] = useState(null);
  const [view, setView] = useState("dashboard");

  if (view === "topology") return (
    <div style={{ flex:1, display:"flex", flexDirection:"column", overflow:"hidden" }}>
      <div style={{ background:"#fff", borderBottom:"1px solid #e5e7eb", padding:"8px 16px", display:"flex", alignItems:"center", gap:10 }}>
        <button onClick={()=>setView("dashboard")} style={{ background:"#f3f4f6", border:"1px solid #e5e7eb", borderRadius:6, padding:"6px 12px", cursor:"pointer", fontSize:12, fontWeight:600, color:"#374151", display:"flex", alignItems:"center", gap:5 }}>
          <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="15 18 9 12 15 6"/></svg>
          Dashboard
        </button>
        <div style={{ fontSize:14, fontWeight:700, color:"#111827" }}>Network Topology Builder</div>
        <div style={{ fontSize:11, color:"#9ca3af" }}>Drag devices — Double-click to open terminal — Link tool to connect</div>
      </div>
      <TopologyBuilder />
    </div>
  );

  const configCards = [
    { id:"ip", color:"#1d4ed8", title:"Set IP Address", desc:"Assign IP to interface", icon:<><rect x="2" y="3" width="20" height="14" rx="2"/><path d="M8 21h8M12 17v4"/></> },
    { id:"port", color:"#15803d", title:"Enable / Disable Port", desc:"Control port state", icon:<><path d="M18.36 6.64a9 9 0 1 1-12.73 0"/><line x1="12" y1="2" x2="12" y2="12"/></> },
    { id:"vlan", color:"#0e7490", title:"Configure VLAN", desc:"Create VLANs and assign ports", icon:<><polygon points="12 2 2 7 12 12 22 7 12 2"/><polyline points="2 17 12 22 22 17"/><polyline points="2 12 12 17 22 12"/></> },
    { id:"hostname", color:"#7c3aed", title:"Change Hostname", desc:"Set device name", icon:<><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></> },
    { id:"save", color:"#92400e", title:"Save Configuration", desc:"Save settings to NVRAM", icon:<><path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2z"/><polyline points="17 21 17 13 7 13 7 21"/><polyline points="7 3 7 8 15 8"/></> },
    { id:"show", color:"#065f46", title:"Show Network Status", desc:"View interfaces, VLANs, config", icon:<><polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/></> },
    { id:"route", color:"#4f46e5", title:"Static Route", desc:"Add routing table entries", icon:<><line x1="3" y1="12" x2="21" y2="12"/><line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="18" x2="21" y2="18"/></> },
  ];

  const modals = {
    ip: <IPModal onClose={()=>setModal(null)} onCommand={onCommand} />,
    port: <PortModal onClose={()=>setModal(null)} onCommand={onCommand} />,
    vlan: <VLANModal onClose={()=>setModal(null)} onCommand={onCommand} />,
    hostname: <HostnameModal2 onClose={()=>setModal(null)} onCommand={onCommand} />,
    save: <SaveModal onClose={()=>setModal(null)} onCommand={onCommand} />,
    show: <ShowModal onClose={()=>setModal(null)} onCommand={onCommand} />,
    route: <RouteModal onClose={()=>setModal(null)} onCommand={onCommand} />,
  };

  return (
    <div style={{ flex:1, background:"#f8fafc", overflowY:"auto", padding:"24px" }}>
      <div style={{ marginBottom:8 }}>
        <div style={{ fontSize:18, fontWeight:800, color:"#111827" }}>Network Management</div>
        <div style={{ fontSize:12, color:"#9ca3af", marginTop:4 }}>Configure your network device</div>
      </div>
      <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill, minmax(180px, 1fr))", gap:14, marginBottom:32 }}>
        {configCards.map(card => <Card key={card.id} {...card} onClick={()=>setModal(card.id)} />)}
      </div>

      <div style={{ borderTop:"1px solid #e5e7eb", paddingTop:24, marginBottom:16 }}>
        <div style={{ fontSize:18, fontWeight:800, color:"#111827" }}>Network Topology</div>
        <div style={{ fontSize:12, color:"#9ca3af", marginTop:4 }}>Build and simulate your network visually</div>
      </div>
      <button onClick={()=>setView("topology")} style={{ background:"linear-gradient(135deg,#1d4ed8,#0e7490)", border:"none", borderRadius:14, padding:"24px 32px", cursor:"pointer", textAlign:"left", color:"#fff", width:"100%", display:"flex", alignItems:"center", justifyContent:"space-between", boxShadow:"0 8px 24px #1d4ed830" }}
        onMouseEnter={e=>{ e.currentTarget.style.transform="translateY(-2px)"; e.currentTarget.style.boxShadow="0 12px 32px #1d4ed840"; }}
        onMouseLeave={e=>{ e.currentTarget.style.transform="translateY(0)"; e.currentTarget.style.boxShadow="0 8px 24px #1d4ed830"; }}>
        <div>
          <div style={{ fontSize:16, fontWeight:800, marginBottom:6 }}>Topology Builder</div>
          <div style={{ fontSize:12, opacity:0.8 }}>Drag and drop devices — Connect with cables — Open terminal per device</div>
        </div>
        <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ opacity:0.8 }}>
          <polyline points="9 18 15 12 9 6"/>
        </svg>
      </button>

      {modal && modals[modal]}
    </div>
  );
}
